{
  "name": "Lumina Canvas",
  "description": "A high-performance AI image generator and editor that transforms text prompts into stunning visual assets using Gemini 2.5 Flash Image technology."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type AspectRatio = "1:1" | "3:4" | "4:3" | "9:16" | "16:9";

export interface GeneratedImage {
  id: string;
  url: string;
  prompt: string;
  timestamp: number;
  aspectRatio: AspectRatio;
}

export interface AppState {
  images: GeneratedImage[];
  isGenerating: boolean;
  currentPrompt: string;
  selectedRatio: AspectRatio;
  error: string | null;
}

import { GoogleGenAI } from "@google/genai";
import { AspectRatio } from "../types";

const API_KEY = process.env.API_KEY;

export const generateImage = async (prompt: string, aspectRatio: AspectRatio = "1:1"): Promise<string> => {
  if (!API_KEY) {
    throw new Error("API Key is missing. Please ensure process.env.API_KEY is configured.");
  }

  const ai = new GoogleGenAI({ apiKey: API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: prompt }],
      },
      config: {
        imageConfig: {
          aspectRatio: aspectRatio,
        }
      },
    });

    if (!response.candidates || response.candidates.length === 0) {
      throw new Error("No image generated by the model.");
    }

    // Iterate through parts to find the image
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        const base64Data = part.inlineData.data;
        return `data:image/png;base64,${base64Data}`;
      }
    }

    throw new Error("The model response did not contain an image part.");
  } catch (error: any) {
    console.error("Gemini Image Generation Error:", error);
    throw new Error(error.message || "An unexpected error occurred during image generation.");
  }
};

export const editImage = async (
  base64Image: string, 
  instruction: string, 
  aspectRatio: AspectRatio = "1:1"
): Promise<string> => {
  if (!API_KEY) {
    throw new Error("API Key is missing.");
  }

  const ai = new GoogleGenAI({ apiKey: API_KEY });

  // Clean up data URL prefix if present
  const base64Data = base64Image.replace(/^data:image\/\w+;base64,/, "");

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Data,
              mimeType: 'image/png',
            },
          },
          {
            text: instruction,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: aspectRatio,
        }
      }
    });

    for (const part of response.candidates?.[0].content.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    throw new Error("No edited image returned.");
  } catch (error: any) {
    console.error("Gemini Image Editing Error:", error);
    throw new Error(error.message || "Failed to edit image.");
  }
};

import React, { useState, useCallback, useEffect } from 'react';
import { 
  Sparkles, 
  History, 
  Download, 
  RefreshCw, 
  Layers, 
  Trash2, 
  Maximize2,
  AlertCircle,
  Square,
  RectangleHorizontal,
  RectangleVertical,
  Image as ImageIcon
} from 'lucide-react';
import { generateImage, editImage } from './services/geminiService';
import { GeneratedImage, AspectRatio } from './types';

const App: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [images, setImages] = useState<GeneratedImage[]>([]);
  const [selectedRatio, setSelectedRatio] = useState<AspectRatio>("1:1");
  const [error, setError] = useState<string | null>(null);
  const [activeImageId, setActiveImageId] = useState<string | null>(null);

  const activeImage = images.find(img => img.id === activeImageId) || images[0];

  const handleGenerate = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!prompt.trim() || isGenerating) return;

    setIsGenerating(true);
    setError(null);

    try {
      const imageUrl = await generateImage(prompt, selectedRatio);
      const newImage: GeneratedImage = {
        id: crypto.randomUUID(),
        url: imageUrl,
        prompt: prompt,
        timestamp: Date.now(),
        aspectRatio: selectedRatio
      };
      setImages(prev => [newImage, ...prev]);
      setActiveImageId(newImage.id);
      setPrompt('');
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleCreateBlank = async () => {
    setPrompt('A solid, perfectly blank pure white background. Minimalist, clean, flat white color.');
    // Trigger generation next tick
  };

  useEffect(() => {
    if (prompt === 'A solid, perfectly blank pure white background. Minimalist, clean, flat white color.') {
      handleGenerate();
    }
  }, [prompt]);

  const handleDownload = useCallback((url: string, filename: string) => {
    const link = document.createElement('a');
    link.href = url;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  }, []);

  const deleteImage = (id: string) => {
    setImages(prev => prev.filter(img => img.id !== id));
    if (activeImageId === id) setActiveImageId(null);
  };

  return (
    <div className="flex h-screen flex-col bg-[#0a0a0a] text-zinc-100 overflow-hidden">
      {/* Top Header */}
      <header className="flex h-16 items-center justify-between border-b border-zinc-800/50 bg-[#0a0a0a]/80 px-6 backdrop-blur-md sticky top-0 z-50">
        <div className="flex items-center gap-2">
          <div className="flex h-8 w-8 items-center justify-center rounded-lg bg-indigo-600 shadow-lg shadow-indigo-500/20">
            <Sparkles className="h-5 w-5 text-white" />
          </div>
          <h1 className="text-xl font-bold tracking-tight">Lumina <span className="text-indigo-400">Canvas</span></h1>
        </div>
        <div className="flex items-center gap-4">
          <button 
            onClick={handleCreateBlank}
            className="hidden sm:flex items-center gap-2 rounded-full border border-zinc-700 bg-zinc-900 px-4 py-1.5 text-sm font-medium hover:bg-zinc-800 transition-colors"
          >
            <Square className="h-4 w-4" />
            Quick White Blank
          </button>
          <div className="h-8 w-8 rounded-full bg-zinc-800 border border-zinc-700 flex items-center justify-center overflow-hidden">
             <div className="w-full h-full bg-gradient-to-br from-indigo-500 to-purple-500 opacity-50" />
          </div>
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        {/* Left Sidebar - History */}
        <aside className="hidden w-72 flex-col border-r border-zinc-800/50 bg-[#0c0c0c] md:flex">
          <div className="flex items-center gap-2 p-4 border-b border-zinc-800/50">
            <History className="h-4 w-4 text-zinc-400" />
            <h2 className="text-sm font-semibold text-zinc-400 uppercase tracking-wider">History</h2>
          </div>
          <div className="flex-1 overflow-y-auto p-4 space-y-4">
            {images.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-40 text-center text-zinc-600">
                <ImageIcon className="h-8 w-8 mb-2 opacity-20" />
                <p className="text-xs">No generations yet.</p>
              </div>
            ) : (
              images.map(img => (
                <div 
                  key={img.id}
                  onClick={() => setActiveImageId(img.id)}
                  className={`group relative cursor-pointer overflow-hidden rounded-xl border transition-all duration-300 ${
                    activeImageId === img.id ? 'border-indigo-500 ring-1 ring-indigo-500' : 'border-zinc-800 hover:border-zinc-700'
                  }`}
                >
                  <img src={img.url} alt={img.prompt} className="h-32 w-full object-cover" />
                  <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                    <button 
                      onClick={(e) => { e.stopPropagation(); deleteImage(img.id); }}
                      className="p-2 bg-red-500/20 text-red-400 rounded-lg hover:bg-red-500/40 transition-colors"
                    >
                      <Trash2 className="h-4 w-4" />
                    </button>
                  </div>
                  <div className="p-2 text-[10px] text-zinc-500 truncate bg-zinc-900/50 backdrop-blur-sm">
                    {img.prompt}
                  </div>
                </div>
              ))
            )}
          </div>
        </aside>

        {/* Main Canvas Area */}
        <section className="flex flex-1 flex-col relative">
          <div className="flex-1 flex items-center justify-center p-8 bg-[#0a0a0a] bg-[radial-gradient(#1a1a1a_1px,transparent_1px)] [background-size:24px_24px]">
            {isGenerating ? (
              <div className="flex flex-col items-center gap-6">
                <div className="relative">
                  <div className="h-24 w-24 rounded-full border-4 border-zinc-800 border-t-indigo-500 animate-spin" />
                  <Sparkles className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 h-8 w-8 text-indigo-500 animate-pulse" />
                </div>
                <div className="text-center">
                  <h3 className="text-xl font-medium text-white mb-2">Creating visual magic...</h3>
                  <p className="text-zinc-500 text-sm animate-pulse">Our neural networks are weaving your prompt into pixels.</p>
                </div>
              </div>
            ) : activeImage ? (
              <div className="relative group max-w-4xl w-full">
                <div className="absolute -inset-1 bg-gradient-to-r from-indigo-500 to-purple-500 rounded-2xl blur opacity-10 group-hover:opacity-20 transition duration-1000"></div>
                <div className="relative bg-zinc-900 rounded-xl overflow-hidden shadow-2xl border border-zinc-800">
                  <img 
                    src={activeImage.url} 
                    alt={activeImage.prompt} 
                    className="w-full h-auto max-h-[70vh] object-contain"
                  />
                  <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                    <button 
                      onClick={() => handleDownload(activeImage.url, `lumina-${activeImage.id}.png`)}
                      className="p-2 bg-white/10 hover:bg-white/20 backdrop-blur-md rounded-lg text-white transition-all"
                      title="Download"
                    >
                      <Download className="h-5 w-5" />
                    </button>
                    <button className="p-2 bg-white/10 hover:bg-white/20 backdrop-blur-md rounded-lg text-white transition-all" title="Enlarge">
                      <Maximize2 className="h-5 w-5" />
                    </button>
                  </div>
                </div>
                <div className="mt-4 flex items-start justify-between">
                  <div className="flex-1 pr-4">
                    <h4 className="text-sm font-medium text-zinc-400 mb-1">Prompt:</h4>
                    <p className="text-zinc-200 text-sm italic">"{activeImage.prompt}"</p>
                  </div>
                  <div className="flex items-center gap-4 text-xs font-mono text-zinc-500">
                    <span>Ratio: {activeImage.aspectRatio}</span>
                    <span>{new Date(activeImage.timestamp).toLocaleTimeString()}</span>
                  </div>
                </div>
              </div>
            ) : (
              <div className="max-w-md text-center">
                <div className="inline-flex h-16 w-16 items-center justify-center rounded-2xl bg-zinc-900 border border-zinc-800 mb-6">
                   <Sparkles className="h-8 w-8 text-zinc-700" />
                </div>
                <h2 className="text-2xl font-bold text-white mb-4">Unleash Your Imagination</h2>
                <p className="text-zinc-400 text-sm leading-relaxed mb-8">
                  Describe what you want to see, or start with a simple request like 
                  <span className="text-indigo-400 cursor-pointer hover:underline" onClick={handleCreateBlank}> "create white blank image"</span>.
                </p>
              </div>
            )}
          </div>

          {/* Prompt Input Container - Sticky Bottom */}
          <div className="p-6 bg-[#0a0a0a]/80 border-t border-zinc-800/50 backdrop-blur-xl">
            {error && (
              <div className="mb-4 flex items-center gap-2 p-3 rounded-lg bg-red-500/10 border border-red-500/20 text-red-400 text-sm animate-in fade-in slide-in-from-bottom-2">
                <AlertCircle className="h-4 w-4" />
                {error}
              </div>
            )}

            <form onSubmit={handleGenerate} className="max-w-4xl mx-auto space-y-4">
              <div className="flex flex-wrap gap-2 mb-2">
                {(["1:1", "4:3", "16:9", "9:16", "3:4"] as AspectRatio[]).map(ratio => (
                  <button
                    key={ratio}
                    type="button"
                    onClick={() => setSelectedRatio(ratio)}
                    className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${
                      selectedRatio === ratio 
                        ? 'bg-indigo-600/20 border-indigo-500 text-indigo-300' 
                        : 'bg-zinc-900 border-zinc-700 text-zinc-500 hover:border-zinc-500'
                    }`}
                  >
                    {ratio === "1:1" && <Square className="h-3 w-3" />}
                    {ratio === "16:9" && <RectangleHorizontal className="h-3 w-3" />}
                    {ratio === "9:16" && <RectangleVertical className="h-3 w-3" />}
                    {ratio}
                  </button>
                ))}
              </div>

              <div className="relative group">
                <div className="absolute -inset-0.5 bg-gradient-to-r from-indigo-500/20 to-purple-500/20 rounded-2xl blur opacity-0 group-focus-within:opacity-100 transition duration-300"></div>
                <div className="relative flex items-center bg-zinc-900 border border-zinc-800 rounded-2xl p-2 pl-4 shadow-xl focus-within:border-indigo-500 transition-all">
                  <input 
                    type="text"
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    placeholder="Describe your masterpiece... (e.g. 'Cyberpunk street in neon rain')"
                    className="flex-1 bg-transparent border-none outline-none text-white text-sm placeholder:text-zinc-600"
                    disabled={isGenerating}
                  />
                  <button 
                    type="submit"
                    disabled={isGenerating || !prompt.trim()}
                    className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 disabled:bg-zinc-800 disabled:text-zinc-600 text-white font-semibold py-2.5 px-6 rounded-xl transition-all shadow-lg shadow-indigo-600/20"
                  >
                    {isGenerating ? (
                      <RefreshCw className="h-4 w-4 animate-spin" />
                    ) : (
                      <Sparkles className="h-4 w-4" />
                    )}
                    <span>Generate</span>
                  </button>
                </div>
              </div>
            </form>
          </div>
        </section>

        {/* Right Sidebar - Controls/Context */}
        <aside className="hidden lg:flex w-64 flex-col border-l border-zinc-800/50 bg-[#0c0c0c]">
          <div className="flex items-center gap-2 p-4 border-b border-zinc-800/50">
            <Layers className="h-4 w-4 text-zinc-400" />
            <h2 className="text-sm font-semibold text-zinc-400 uppercase tracking-wider">Parameters</h2>
          </div>
          <div className="p-4 space-y-6">
            <div>
              <label className="text-xs font-semibold text-zinc-500 mb-3 block">Model Engine</label>
              <div className="bg-zinc-900 rounded-lg p-3 border border-zinc-800">
                <div className="text-xs font-medium text-zinc-200">Gemini 2.5 Flash Image</div>
                <div className="text-[10px] text-zinc-500 mt-1">Real-time latent diffusion</div>
              </div>
            </div>

            <div>
              <label className="text-xs font-semibold text-zinc-500 mb-3 block">Quick Actions</label>
              <div className="grid grid-cols-1 gap-2">
                <button 
                  onClick={handleCreateBlank}
                  className="w-full text-left p-2.5 bg-zinc-900/50 border border-zinc-800 rounded-lg text-xs text-zinc-400 hover:bg-zinc-800 transition-colors flex items-center gap-2"
                >
                  <Square className="h-3.5 w-3.5" />
                  Blank White Image
                </button>
                <button className="w-full text-left p-2.5 bg-zinc-900/50 border border-zinc-800 rounded-lg text-xs text-zinc-400 hover:bg-zinc-800 transition-colors flex items-center gap-2">
                  <ImageIcon className="h-3.5 w-3.5" />
                  Random Inspiration
                </button>
              </div>
            </div>

            <div className="pt-4 border-t border-zinc-800/50">
               <div className="bg-indigo-500/10 p-4 rounded-xl border border-indigo-500/20">
                  <div className="flex items-center gap-2 mb-2">
                    <Sparkles className="h-4 w-4 text-indigo-400" />
                    <span className="text-xs font-bold text-indigo-200">Pro Tip</span>
                  </div>
                  <p className="text-[11px] leading-relaxed text-indigo-300/70">
                    Use specific keywords like "4k", "cinematic lighting", or "octane render" for higher detail results.
                  </p>
               </div>
            </div>
          </div>

          <div className="mt-auto p-4 border-t border-zinc-800/50">
            <div className="flex items-center justify-between text-[10px] text-zinc-600">
              <span>v1.0.4 Stable</span>
              <span className="flex items-center gap-1">
                <div className="h-1.5 w-1.5 rounded-full bg-green-500" /> 
                System Ready
              </span>
            </div>
          </div>
        </aside>
      </main>
    </div>
  );
};

export default App;

